We have a special arrangement (since 2018) for dynamically adding ConfigScaleOut action name to the actions names list only if the CDT application properties file (cdt.application.properties.json) contains property like: "displayConfigScaleout": true.  This is achieved via the following lines of code in src/app/vnfs/build-artifacts/reference-dataform/reference-dataform.component.ts :
 . . .
    ngOnInit() {
      let methName= "ngOnInit";
      if( this.utilityService.getTracelvl() > 0 )
        console.log( this.classNm+": "+methName+": start ");
        // this.handleVMBlockDisplay();
      //.. initializing the variables and checking for configscaleout fromm properties file
      this.configScaleOutExist=
        require('../../../../cdt.application.properties.json').displayConfigScaleout;
      if( this.utilityService.getTracelvl() > 0 )
        console.log( this.classNm+": "+methName+
          ": configScaleOutExist:["+this.configScaleOutExist+"]");
      if( this.configScaleOutExist) {
        this.actions.push( 'ConfigScaleOut' );
      };
